int _mangaSeriesEstimateSize(
  MangaSeries object,
  List<int> offsets,
  Map<Type, List<int>> allOffsets,
) {
  var bytesCount = offsets.last;
  {
    final value = object.anilistId;
    if (value != null) {
      bytesCount += 3 + value.length * 3;
    }
  }
  bytesCount += 3 + object.author.length * 3;
  bytesCount += 3 + object.coverPath.length * 3;
  bytesCount += 3 + object.description.length * 3;
  {
    final value = object.malId;
    if (value != null) {
      bytesCount += 3 + value.length * 3;
    }
  }
  {
    final value = object.onlineCoverUrl;
    if (value != null) {
      bytesCount += 3 + value.length * 3;
    }
  }
  {
    final value = object.progress;
    if (value != null) {
      bytesCount += 3 +
          IsarUserProgressSchema.estimateSize(
              value, allOffsets[IsarUserProgress]!, allOffsets);
    }
  }
  bytesCount += 3 + object.seriesId.length * 3;
  bytesCount += 3 + object.title.length * 3;
  return bytesCount;
}

void _mangaSeriesSerialize(
  MangaSeries object,
  IsarWriter writer,
  List<int> offsets,
  Map<Type, List<int>> allOffsets,
) {
  writer.writeString(offsets[0], object.anilistId);
  writer.writeString(offsets[1], object.author);
  writer.writeString(offsets[2], object.coverPath);
  writer.writeString(offsets[3], object.description);
  writer.writeLong(offsets[4], object.libraryConfigId);
  writer.writeString(offsets[5], object.malId);
  writer.writeString(offsets[6], object.onlineCoverUrl);
  writer.writeObject<IsarUserProgress>(
    offsets[7],
    allOffsets,
    IsarUserProgressSchema.serialize,
    object.progress,
  );
  writer.writeString(offsets[8], object.seriesId);
  writer.writeString(offsets[9], object.title);
}

