int _chapterPageEstimateSize(
  ChapterPage object,
  List<int> offsets,
  Map<Type, List<int>> allOffsets,
) {
  var bytesCount = offsets.last;
  bytesCount += 3 + object.chapterId.length * 3;
  bytesCount += 3 + object.pageFilePath.length * 3;
  bytesCount += 3 + object.pageId.length * 3;
  bytesCount += 3 + object.panelRawJson.length * 3;
  {
    for (var i = 0; i < object.panelRawJson.length; i++) {
      final value = object.panelRawJson[i];
      bytesCount += value.length * 3;
    }
  }
  return bytesCount;
}

void _chapterPageSerialize(
  ChapterPage object,
  IsarWriter writer,
  List<int> offsets,
  Map<Type, List<int>> allOffsets,
) {
  writer.writeString(offsets[0], object.chapterId);
  writer.writeString(offsets[1], object.pageFilePath);
  writer.writeString(offsets[2], object.pageId);
  writer.writeLong(offsets[3], object.pageNumber);
  writer.writeStringList(offsets[4], object.panelRawJson);
}

ChapterPage _chapterPageDeserialize(
  Id id,
  IsarReader reader,
  List<int> offsets,
  Map<Type, List<int>> allOffsets,
) {
  final object = ChapterPage();
  object.chapterId = reader.readString(offsets[0]);
  object.id = id;
  object.pageFilePath = reader.readString(offsets[1]);
  object.pageId = reader.readString(offsets[2]);
  object.pageNumber = reader.readLong(offsets[3]);
  object.panelRawJson = reader.readStringList(offsets[4]) ?? [];
  return object;
}

P _chapterPageDeserializeProp<P>(
  IsarReader reader,
  int propertyId,
  int offset,
  Map<Type, List<int>> allOffsets,
) {
  switch (propertyId) {
    case 0:
      return (reader.readString(offset)) as P;
    case 1:
      return (reader.readString(offset)) as P;
    case 2:
      return (reader.readString(offset)) as P;
    case 3:
      return (reader.readLong(offset)) as P;
    case 4:
      return (reader.readStringList(offset) ?? []) as P;
    default:
