int _creatorEstimateSize(
  Creator object,
  List<int> offsets,
  Map<Type, List<int>> allOffsets,
) {
  var bytesCount = offsets.last;
  bytesCount += 3 + object.creditId.length * 3;
  bytesCount += 3 + object.name.length * 3;
  {
    final value = object.profilePath;
    if (value != null) {
      bytesCount += 3 + value.length * 3;
    }
  }
  return bytesCount;
}

void _creatorSerialize(
  Creator object,
  IsarWriter writer,
  List<int> offsets,
  Map<Type, List<int>> allOffsets,
) {
  writer.writeString(offsets[0], object.creditId);
  writer.writeLong(offsets[1], object.gender);
  writer.writeLong(offsets[2], object.id);
  writer.writeString(offsets[3], object.name);
  writer.writeString(offsets[4], object.profilePath);
}

Creator _creatorDeserialize(
  Id id,
  IsarReader reader,
  List<int> offsets,
  Map<Type, List<int>> allOffsets,
) {
  final object = Creator();
  object.creditId = reader.readString(offsets[0]);
  object.gender = reader.readLong(offsets[1]);
  object.id = reader.readLong(offsets[2]);
  object.name = reader.readString(offsets[3]);
  object.profilePath = reader.readStringOrNull(offsets[4]);
